// Compute today's date range in SGT (UTC+7)
const now = new Date();
const SGT_OFFSET = 7 * 60 * 60 * 1000;
const sgtNow = new Date(now.getTime() + SGT_OFFSET);
const sgtDateStr = sgtNow.toISOString().split('T')[0]; // YYYY-MM-DD

const startDate = new Date(sgtDateStr + 'T00:00:00+07:00').toISOString();
const endDate = now.toISOString();

// Format: DD/MM/YYYY
const [yyyy, mm, dd] = sgtDateStr.split('-');
const dateDisplay = `${dd}/${mm}/${yyyy}`;

return [{
  json: {
    start_date: startDate,
    end_date: endDate,
    date_display: dateDisplay
  }
}];

// === ĐỌC DỮ LIỆU ===
// responseFormat: text → $json.data là raw JSON string, luôn có 1 item dù kết quả rỗng
const candidatesRaw = $('Query Candidates').first().json.data || '[]';
const ordersRaw = $json.data || '[]';
const dateDisplay = $('Tính Ngày').first().json.date_display;

const candidates = JSON.parse(candidatesRaw);
const orders = JSON.parse(ordersRaw);

// === TẠO TIN NHẮN ===
let text = `📊 *BÁO CÁO NGÀY ${dateDisplay}*\n`;
text += `━━━━━━━━━━━━━━━━━━\n\n`;

// --- Phần 1: Ứng viên mới ---
if (!Array.isArray(candidates) || candidates.length === 0) {
  text += `🆕 *Ứng viên mới hôm nay:* Không có\n`;
} else {
  text += `🆕 *Ứng viên mới hôm nay: ${candidates.length} người*\n`;

  const byOrder = {};
  for (const c of candidates) {
    const key = c.order_id || 'Chưa phân đơn';
    if (!byOrder[key]) byOrder[key] = { pass: 0, fail: 0, pending: 0 };
    const status = (c.interview_status || '').toLowerCase();
    if (status === 'pass') byOrder[key].pass++;
    else if (status === 'fail') byOrder[key].fail++;
    else byOrder[key].pending++;
  }

  for (const [orderId, stats] of Object.entries(byOrder)) {
    const total = stats.pass + stats.fail + stats.pending;
    const parts = [];
    if (stats.pass > 0) parts.push(`✅ ${stats.pass}`);
    if (stats.fail > 0) parts.push(`❌ ${stats.fail}`);
    if (stats.pending > 0) parts.push(`⏳ ${stats.pending}`);
    text += `  📦 ${orderId}: ${total} người — ${parts.join(' / ') || '⏳ chờ duyệt'}\n`;
  }
}

text += `\n`;

// --- Phần 2: Đơn hàng đang tuyển ---
if (!Array.isArray(orders) || orders.length === 0) {
  text += `📋 *Đơn hàng:* Tất cả đã đủ lao động 🎉`;
} else {
  const totalMissing = orders.reduce((sum, o) => sum + (parseInt(o.labor_missing) || 0), 0);
  text += `📋 *Đơn hàng đang tuyển: ${orders.length} đơn — còn thiếu ${totalMissing} suất*\n`;

  for (const o of orders.slice(0, 8)) {
    text += `  • ${o.company_name} — ${o.job_type}\n    còn thiếu *${o.labor_missing}/${o.total_labor}* suất\n`;
  }
  if (orders.length > 8) {
    text += `  _...và ${orders.length - 8} đơn khác_\n`;
  }
}

return [{
  json: {
    text,
    chat_id: '-5163098733'
  }
}];
